import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Cart() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  if (!cart.toppings) {
    return (
      <div className="max-w-md mx-auto min-h-screen bg-gray-50">
        {/* Navy Header */}
        <div className="bg-navy px-5 pt-5 pb-4 flex items-center gap-3">
          <button
            onClick={() => navigate('/')}
            className="text-white/70 hover:text-white text-xl transition"
          >
            ←
          </button>
          <h1 className="text-white text-xl font-black">העגלה שלי</h1>
        </div>

        <div className="flex flex-col items-center justify-center py-28 text-center px-8">
          <div className="text-7xl mb-4">🛒</div>
          <p className="text-xl font-bold text-gray-700 mb-2">העגלה ריקה</p>
          <p className="text-gray-400 text-sm mb-7">הוסיפו פיצה כדי להמשיך</p>
          <button
            onClick={() => navigate('/')}
            className="bg-tomato text-white px-8 py-3.5 rounded-2xl font-black text-lg shadow-md hover:bg-red-700 transition active:scale-95"
          >
            לתפריט
          </button>
        </div>
      </div>
    );
  }

  const BASE_PRICE = 30;
  const TOPPING_PRICE = 8;

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50">

      {/* Navy Header */}
      <div className="bg-navy px-5 pt-5 pb-4 flex items-center gap-3">
        <button
          onClick={() => navigate('/')}
          className="text-white/70 hover:text-white text-xl transition"
        >
          ←
        </button>
        <h1 className="text-white text-xl font-black">העגלה שלי</h1>
      </div>

      <div className="px-4 pt-4 space-y-3 pb-8">

        {/* Pizza Summary Card */}
        <div className="bg-white rounded-2xl shadow-md overflow-hidden">
          <div className="flex gap-4 p-4">
            <img
              src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=120&q=80"
              alt="pizza"
              className="w-20 h-20 rounded-xl object-cover flex-shrink-0"
            />
            <div className="flex-1 min-w-0">
              <h3 className="font-black text-gray-900 text-lg">פיצה קלאסית</h3>
              <p className="text-gray-400 text-xs mt-0.5">בצק טרי, רוטב ביתי, מוצרלה</p>
              {cart.toppings.length > 0 && (
                <p className="text-gray-600 text-xs mt-1.5 leading-relaxed">
                  + {cart.toppings.join(', ')}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Price Breakdown */}
        <div className="bg-white rounded-2xl shadow-sm p-4 space-y-2">
          <h3 className="font-bold text-gray-800 mb-3">סיכום הזמנה</h3>

          <div className="flex justify-between text-sm text-gray-600">
            <span>פיצה בסיסית</span>
            <span>{BASE_PRICE}₪</span>
          </div>

          {cart.toppings.map(t => (
            <div key={t} className="flex justify-between text-sm text-gray-500">
              <span>+ {t}</span>
              <span>+{TOPPING_PRICE}₪</span>
            </div>
          ))}

          <div className="border-t border-gray-100 pt-3 flex justify-between items-center">
            <span className="font-black text-gray-900 text-lg">סה"כ</span>
            <span className="font-black text-tomato text-2xl">{cart.total}₪</span>
          </div>
        </div>

        {/* Edit button */}
        <button
          onClick={() => navigate('/')}
          className="w-full py-3 rounded-2xl border-2 border-gray-200 text-gray-600 font-bold text-sm hover:border-gray-300 transition bg-white"
        >
          ✏️ ערוך הזמנה
        </button>

        {/* Checkout CTA */}
        <button
          onClick={() => navigate('/checkout')}
          className="w-full bg-tomato text-white py-4 rounded-2xl font-black text-xl shadow-md hover:bg-red-700 transition active:scale-95 flex items-center justify-between px-6"
        >
          <span>לתשלום</span>
          <span className="bg-white/20 px-3 py-1 rounded-xl font-bold text-lg">{cart.total}₪</span>
        </button>
      </div>
    </div>
  );
}
